import { delegate } from '@dcyfr/ai';

const result = await delegate({
  to: 'documentation-expert',
  intent: 'Generate API reference for @dcyfr/ai exports',
  inputs: {
    packagePath: './dcyfr-ai/src',
    format: 'markdown',
  },
  expectedOutputs: {
    type: 'markdown',
    minLength: 500,
  },
  timeoutMs: 30_000,
  fallbackBehavior: 'return-partial',
});

console.log(result.output);
console.log('Duration:', result.durationMs, 'ms');

import { createCheckpoint, loadCheckpoint } from '@dcyfr/ai';

// --- At pause point ---
const checkpoint = createCheckpoint({
  goal: 'Refactor auth module',
  completedSteps: [
    'Read src/auth/jwt.ts — found missing expiry validation',
    'Updated jwt.ts with validateExpiry() call',
  ],
  openQuestions: [
    'Does refreshToken flow also bypass expiry check?',
  ],
  keyFacts: {
    affectedFiles: ['src/auth/jwt.ts', 'src/auth/refresh.ts'],
    breakingChange: false,
  },
});

await checkpoint.save('auth-refactor-session-1');

// --- On next invocation ---
const state = await loadCheckpoint('auth-refactor-session-1');
console.log('Resuming:', state.goal);
console.log('Open questions:', state.openQuestions);

import { createRagPipeline } from '@dcyfr/ai-rag';

const rag = createRagPipeline({
  vectorStore: 'chroma',
  collection: 'dcyfr-docs',
  model: 'claude-sonnet-4-6',
  topK: 5,
  scoreThreshold: 0.7,
});

const response = await rag.query({
  question: 'How does the delegation framework handle TLP clearance?',
  systemPrompt: 'You are a helpful assistant. Answer based only on the provided context.',
});

console.log(response.answer);
console.log('Sources:', response.sources.map(s => s.title));
